import React, { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Search, Filter, Briefcase, BookOpen, Star, Trash2,
  Download, Edit, Plus, FileText, Clock, SortDesc,
} from 'lucide-react';
import { format } from 'date-fns';
import toast from 'react-hot-toast';
import { documentsAPI } from '../utils/api';

const DocumentsPage = () => {
  const navigate = useNavigate();
  const [docs, setDocs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [filter, setFilter] = useState('all'); // all | resume | blog | favorite
  const [pagination, setPagination] = useState({ page: 1, pages: 1, total: 0 });
  const [deleting, setDeleting] = useState(null);

  const fetchDocs = useCallback(async (page = 1) => {
    setLoading(true);
    try {
      const params = { page, limit: 12 };
      if (search) params.search = search;
      if (filter === 'resume' || filter === 'blog') params.type = filter;
      if (filter === 'favorite') params.favorite = true;

      const { data } = await documentsAPI.getAll(params);
      setDocs(data.documents);
      setPagination(data.pagination);
    } catch {
      toast.error('Failed to load documents.');
    } finally {
      setLoading(false);
    }
  }, [search, filter]);

  useEffect(() => {
    const t = setTimeout(() => fetchDocs(1), 300);
    return () => clearTimeout(t);
  }, [fetchDocs]);

  const handleDelete = async (docId, title) => {
    if (!window.confirm(`Delete "${title}"? This cannot be undone.`)) return;
    setDeleting(docId);
    try {
      await documentsAPI.delete(docId);
      setDocs(prev => prev.filter(d => d._id !== docId));
      toast.success('Document deleted.');
    } catch {
      toast.error('Failed to delete document.');
    } finally {
      setDeleting(null);
    }
  };

  const handleExportPDF = async (docId, title) => {
    try {
      toast.loading('Preparing PDF...', { id: `pdf-${docId}` });
      const res = await documentsAPI.exportPDF(docId);
      const url = window.URL.createObjectURL(new Blob([res.data]));
      const a = document.createElement('a');
      a.href = url;
      a.download = `${title.replace(/[^a-z0-9]/gi, '_')}.pdf`;
      a.click();
      window.URL.revokeObjectURL(url);
      toast.success('PDF downloaded!', { id: `pdf-${docId}` });
    } catch {
      toast.error('Export failed.', { id: `pdf-${docId}` });
    }
  };

  const handleToggleFavorite = async (doc) => {
    try {
      await documentsAPI.update(doc._id, { isFavorite: !doc.isFavorite });
      setDocs(prev => prev.map(d =>
        d._id === doc._id ? { ...d, isFavorite: !d.isFavorite } : d
      ));
    } catch {
      toast.error('Failed to update favourite.');
    }
  };

  const filters = [
    { key: 'all', label: 'All', icon: FileText },
    { key: 'resume', label: 'Resumes', icon: Briefcase },
    { key: 'blog', label: 'Blogs', icon: BookOpen },
    { key: 'favorite', label: 'Favourites', icon: Star },
  ];

  return (
    <div className="container" style={{ paddingTop: '40px', paddingBottom: '60px' }}>
      {/* Header */}
      <div className="fade-in" style={{
        display: 'flex', alignItems: 'center',
        justifyContent: 'space-between', marginBottom: '28px', flexWrap: 'wrap', gap: '12px',
      }}>
        <div>
          <h1 style={{ fontSize: '28px', letterSpacing: '-0.03em' }}>My Documents</h1>
          <p style={{ color: 'var(--text-muted)', fontSize: '14px', marginTop: '4px' }}>
            {pagination.total} document{pagination.total !== 1 ? 's' : ''} total
          </p>
        </div>
        <button className="btn btn-primary" onClick={() => navigate('/generate')}>
          <Plus size={16} /> New Document
        </button>
      </div>

      {/* Search + Filters */}
      <div className="fade-in fade-in-delay-1" style={{
        display: 'flex', gap: '12px', marginBottom: '24px', flexWrap: 'wrap',
      }}>
        <div style={{ position: 'relative', flex: '1', minWidth: '220px' }}>
          <Search size={16} style={{
            position: 'absolute', left: '14px', top: '50%',
            transform: 'translateY(-50%)', color: 'var(--text-muted)',
          }} />
          <input
            className="input"
            placeholder="Search documents..."
            value={search}
            onChange={e => setSearch(e.target.value)}
            style={{ paddingLeft: '42px' }}
          />
        </div>

        <div style={{ display: 'flex', gap: '6px', flexWrap: 'wrap' }}>
          {filters.map(({ key, label, icon: Icon }) => (
            <button
              key={key}
              className="btn"
              onClick={() => setFilter(key)}
              style={{
                background: filter === key ? 'var(--accent)' : 'var(--bg-input)',
                color: filter === key ? 'white' : 'var(--text-secondary)',
                border: filter === key ? '1px solid var(--accent)' : '1px solid var(--border)',
                fontSize: '13px',
                padding: '8px 14px',
                boxShadow: filter === key ? '0 0 16px var(--accent-glow)' : 'none',
              }}
            >
              <Icon size={14} />
              {label}
            </button>
          ))}
        </div>
      </div>

      {/* Docs Grid */}
      {loading ? (
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
          gap: '16px',
        }}>
          {[...Array(6)].map((_, i) => (
            <div key={i} style={{
              height: '160px',
              background: 'var(--bg-card)',
              border: '1px solid var(--border)',
              borderRadius: 'var(--radius-lg)',
              animation: 'pulse 1.5s ease infinite',
            }} />
          ))}
        </div>
      ) : docs.length === 0 ? (
        <div style={{ textAlign: 'center', padding: '80px 20px' }}>
          <FileText size={48} color="var(--text-muted)" style={{ margin: '0 auto 16px' }} />
          <h3 style={{ fontSize: '20px', marginBottom: '8px' }}>
            {search || filter !== 'all' ? 'No documents match your search' : 'No documents yet'}
          </h3>
          <p style={{ color: 'var(--text-muted)', marginBottom: '24px', fontSize: '14px' }}>
            {search || filter !== 'all' ? 'Try a different search or filter.' : 'Generate your first AI document to get started.'}
          </p>
          <button className="btn btn-primary" onClick={() => navigate('/generate')}>
            <Plus size={16} /> Generate Document
          </button>
        </div>
      ) : (
        <>
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
            gap: '16px',
          }}>
            {docs.map((doc, idx) => (
              <div
                key={doc._id}
                className={`card fade-in fade-in-delay-${Math.min(idx + 1, 3)}`}
                style={{ cursor: 'pointer', display: 'flex', flexDirection: 'column', gap: '14px' }}
                onClick={() => navigate(`/editor/${doc._id}`)}
              >
                {/* Card Header */}
                <div style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', gap: '10px' }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '10px', minWidth: 0 }}>
                    <div style={{
                      width: '36px', height: '36px', flexShrink: 0,
                      background: doc.type === 'resume' ? 'rgba(108,99,255,0.15)' : 'rgba(67,217,162,0.12)',
                      borderRadius: '10px',
                      display: 'flex', alignItems: 'center', justifyContent: 'center',
                    }}>
                      {doc.type === 'resume'
                        ? <Briefcase size={16} color="var(--accent)" />
                        : <BookOpen size={16} color="var(--accent-green)" />}
                    </div>
                    <span className={`badge badge-${doc.type}`}>{doc.type}</span>
                  </div>
                  <button
                    className="btn btn-ghost"
                    style={{ padding: '4px', flexShrink: 0 }}
                    onClick={e => { e.stopPropagation(); handleToggleFavorite(doc); }}
                  >
                    <Star
                      size={16}
                      fill={doc.isFavorite ? 'var(--accent-yellow)' : 'none'}
                      color={doc.isFavorite ? 'var(--accent-yellow)' : 'var(--text-muted)'}
                    />
                  </button>
                </div>

                {/* Title */}
                <h3 style={{
                  fontSize: '16px',
                  fontWeight: '700',
                  overflow: 'hidden',
                  display: '-webkit-box',
                  WebkitLineClamp: 2,
                  WebkitBoxOrient: 'vertical',
                  lineHeight: '1.4',
                }}>
                  {doc.title}
                </h3>

                {/* Footer */}
                <div style={{
                  display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                  marginTop: 'auto',
                }}>
                  <span style={{ fontSize: '12px', color: 'var(--text-muted)', display: 'flex', alignItems: 'center', gap: '4px' }}>
                    <Clock size={11} />
                    {format(new Date(doc.updatedAt), 'MMM d, yyyy')}
                  </span>
                  <div style={{ display: 'flex', gap: '4px' }}>
                    <button className="btn btn-ghost" style={{ padding: '6px' }}
                      onClick={e => { e.stopPropagation(); navigate(`/editor/${doc._id}`); }}
                      title="Edit">
                      <Edit size={14} />
                    </button>
                    <button className="btn btn-ghost" style={{ padding: '6px' }}
                      onClick={e => { e.stopPropagation(); handleExportPDF(doc._id, doc.title); }}
                      title="Export PDF">
                      <Download size={14} />
                    </button>
                    <button className="btn btn-ghost" style={{ padding: '6px', color: 'var(--accent-secondary)' }}
                      onClick={e => { e.stopPropagation(); handleDelete(doc._id, doc.title); }}
                      disabled={deleting === doc._id}
                      title="Delete">
                      {deleting === doc._id
                        ? <div className="spinner" style={{ width: '14px', height: '14px' }} />
                        : <Trash2 size={14} />}
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>

          {/* Pagination */}
          {pagination.pages > 1 && (
            <div style={{ display: 'flex', justifyContent: 'center', gap: '8px', marginTop: '32px' }}>
              {Array.from({ length: pagination.pages }, (_, i) => i + 1).map(p => (
                <button
                  key={p}
                  className="btn"
                  onClick={() => fetchDocs(p)}
                  style={{
                    padding: '8px 14px',
                    background: p === pagination.page ? 'var(--accent)' : 'var(--bg-input)',
                    color: p === pagination.page ? 'white' : 'var(--text-secondary)',
                    border: '1px solid var(--border)',
                    fontSize: '13px',
                  }}
                >
                  {p}
                </button>
              ))}
            </div>
          )}
        </>
      )}

      <style>{`
        @keyframes pulse {
          0%, 100% { opacity: 1; }
          50% { opacity: 0.5; }
        }
      `}</style>
    </div>
  );
};

export default DocumentsPage;
